#include <bits/stdc++.h>
using namespace std;
struct xs{
	string name;
	int yw=-1,sx=-1,yy=-1;
	int zf(){
		return yw+sx+yy;
	};
}aa[1005],k;
int n;
int main() {
	cin>>n;
	for(int i=0;i<n;i++){
		cin>>aa[i].name>>aa[i].yw>>aa[i].sx>>aa[i].yy;
		if(k.zf()<aa[i].zf()){
			k=aa[i];
		}
	}
	cout<<k.name<<" "<<k.yw<<" "<<k.sx<<" "<<k.yy;
	return 0;
}
